import{_ as t,o as e,c as n,a0 as r}from"./chunks/framework.CSK6mTG2.js";const q=JSON.parse('{"title":"混合注意力：滑动窗口与全局注意力的\\"精读与概览\\"","description":"","frontmatter":{"title":"混合注意力：滑动窗口与全局注意力的\\"精读与概览\\"","author":"唐超","date":"2026-07-11T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/hybrid-attention.md","filePath":"menuAI/hybrid-attention.md"}'),a={name:"menuAI/hybrid-attention.md"};function i(l,o,s,d,u,p){return e(),n("div",null,[...o[0]||(o[0]=[r('<h1 id="混合注意力-滑动窗口与全局注意力的-精读与概览" tabindex="-1">混合注意力：滑动窗口与全局注意力的&quot;精读与概览&quot; <a class="header-anchor" href="#混合注意力-滑动窗口与全局注意力的-精读与概览" aria-label="Permalink to &quot;混合注意力：滑动窗口与全局注意力的&quot;精读与概览&quot;&quot;">​</a></h1><p>你读这篇文章的时候，其实在做两件事：<strong>精读</strong>当前这句话，同时<strong>扫一眼</strong>前后段落知道上下文在讲什么。这两件事的认知负担完全不同——精读需要逐字分析，扫读只需要知道大概在说什么。</p><p>大模型的注意力机制也面临同样的问题。如果把所有 token 一次性做全局注意力（每两个词都要互相&quot;打招呼&quot;），计算量会爆炸；但如果只盯着最近几个词看，又容易丢了远距离的上下文关系。</p><p>所以聪明的研究者想出了一个办法：<strong>混合注意力</strong>——让模型同时拥有&quot;精读&quot;和&quot;概览&quot;两种模式。这篇文章就来讲讲这个思路。</p><h2 id="想象一个双轨阅读器" tabindex="-1">想象一个双轨阅读器 <a class="header-anchor" href="#想象一个双轨阅读器" aria-label="Permalink to &quot;想象一个双轨阅读器&quot;">​</a></h2><p>你可以把混合注意力理解为一个<strong>双轨阅读器</strong>：</p><ul><li><strong>滑动窗口注意力（SWA）</strong>：每次只看固定的窗口范围，比如前后各 512 个 token。好比读一本书时，眼睛每次只聚焦在当前段落附近，远处的章节暂时不看。</li><li><strong>全局注意力（GA）</strong>：偶尔停下来，翻回去看目录、前言，或者联系开头埋的伏笔。这是全局的、跨越整篇文章的关联。</li></ul><p>两种注意力<strong>并行工作</strong>，各司其职。局部细节由滑动窗口处理，长距离依赖由全局注意力搭桥。</p><h2 id="滑动窗口注意力-看得近-但看得清" tabindex="-1">滑动窗口注意力：看得近，但看得清 <a class="header-anchor" href="#滑动窗口注意力-看得近-但看得清" aria-label="Permalink to &quot;滑动窗口注意力：看得近，但看得清&quot;">​</a></h2><p>标准的全注意力（Full Attention）会把序列中任意两个 token 都计算一次关联度。如果序列长度是 <code>n</code>，那attention 的计算复杂度是 <code>O(n²)</code>——长度翻倍，计算量翻四倍。这在大模型里是个灾难。</p><p>滑动窗口注意力把每个 token 的视野限制在固定窗口大小 <code>w</code> 内。比如 GPT-4 的某个变体用 8192 的窗口，你当前位置的 token 只能和前后各 8192 个 token 交互，远处的 token 暂时被&quot;忽略&quot;。</p><blockquote><p>打个比方：你在一个图书馆里查资料，全注意力相当于每次借阅都要向全馆广播&quot;我想找所有书里和这本最相关的内容&quot;；滑动窗口相当于你只向你左右相邻的几排书架去问，效率高多了。</p></blockquote><p>计算复杂度从 <code>O(n²)</code> 降到了 <code>O(n·w)</code>，而 <code>w</code> 通常远小于 <code>n</code>。</p><p>但这里有个问题：<strong>信息怎么从第 1 个 token 传到第 10000 个 token？</strong> 如果只有滑动窗口，远处的 token 永远无法影响当前 token——模型就成了&quot;近视眼&quot;。</p><h2 id="全局注意力-偶尔拉通全场的-大会" tabindex="-1">全局注意力：偶尔拉通全场的&quot;大会&quot; <a class="header-anchor" href="#全局注意力-偶尔拉通全场的-大会" aria-label="Permalink to &quot;全局注意力：偶尔拉通全场的&quot;大会&quot;&quot;">​</a></h2><p>全局注意力的出现就是为了解决长距离依赖。它允许某些特殊的 token（通常是特殊标记，如 <code>[CLS]</code>、<code>[G]</code> 或者第一层的某些 token）能够看到序列中的所有其他 token，并被所有 token 看到。</p><p>你可以理解为：<strong>模型里安插了几个&quot;记者&quot;token</strong>，它们分布在序列的关键位置，任务就是把所有信息收集起来，然后广播给其他人。这些记者 token 就像神经网络里的 hub 节点——它们的注意力范围是全局的。</p><p>实际上，许多现代大模型（如 Mistral、Qwen 等）会在<strong>每一层</strong>都使用滑动窗口注意力，同时在某些特定层或特定 token 上加入全局注意力能力。每一层的 SWA 负责局部精读，逐层往上传递信息；全局注意力负责远距离的&quot;大局观&quot;。</p><h2 id="两种注意力的融合方式" tabindex="-1">两种注意力的融合方式 <a class="header-anchor" href="#两种注意力的融合方式" aria-label="Permalink to &quot;两种注意力的融合方式&quot;">​</a></h2><p>混合注意力不是简单地把两种注意力拼在一起，而是有几种典型的融合策略：</p><p><strong>1. 交替堆叠（Stacking）</strong> Transformer 的某些变体（如 Longformer）会让不同的注意力层交替使用 SWA 和 GA。低层用滑动窗口提取局部特征，高层用全局注意力整合远距离信息。就像人读书，先逐段细读，最后整体回顾总结。</p><p><strong>2. 膨胀滑动窗口（Dilated Sliding Window）</strong> 受膨胀卷积（Dilated Convolution）的启发，跳过某些 token 形成&quot;跳跃式&quot;窗口。比如只看第 1、5、9、13... 个 token，虽然窗口内 token 少了，但覆盖的<strong>感受野</strong>反而更大了。这比固定窗口更高效地捕捉不同范围的依赖关系。</p><p><strong>3. 全局 token + 局部窗口的组合</strong> 比如 BigBird、Longformer 这类模型，在序列里插入少量全局 token（如 <code>[CLS]</code>），它们能直接看到所有 token；同时普通 token 只在局部窗口内交互。信息通过全局 token 像&quot;中转站&quot;一样流通。</p><h2 id="为什么要这样做-聊聊计算量的账" tabindex="-1">为什么要这样做？聊聊计算量的账 <a class="header-anchor" href="#为什么要这样做-聊聊计算量的账" aria-label="Permalink to &quot;为什么要这样做？聊聊计算量的账&quot;">​</a></h2><p>我们来算一笔账，直观感受下混合注意力的价值：</p><p>假设序列长度 <code>n = 16384</code>，窗口大小 <code>w = 512</code>：</p><ul><li><strong>全注意力</strong>：<code>16384 × 16384 ≈ 2.68 亿</code> 次计算</li><li><strong>滑动窗口注意力</strong>：<code>16384 × 512 ≈ 840 万</code> 次计算</li></ul><p>差了约 <strong>32 倍</strong>！而效果上，对于大多数自然语言任务，相邻 token 之间的关联本来就占大多数，全窗口的全局注意力有点&quot;杀鸡用牛刀&quot;的感觉。</p><p>不过，如果任务真的需要跨越超长距离的逻辑关联（比如对比文章开头和结尾的对应关系），纯滑动窗口就会捉襟见肘。这也是为什么需要全局注意力来兜底。</p><h2 id="实际应用-你的模型已经在用它了" tabindex="-1">实际应用：你的模型已经在用它了 <a class="header-anchor" href="#实际应用-你的模型已经在用它了" aria-label="Permalink to &quot;实际应用：你的模型已经在用它了&quot;">​</a></h2><p>你可能已经在用搭载混合注意力的模型了，只是不知道：</p><ul><li><strong>Mistral 7B</strong> 用的 Grouped-Query Attention（GQA）配合滑动窗口，能在 4096 上下文上高效运行。</li><li><strong>Qwen2</strong> 系列在某些配置中使用了局部注意力 + 全局注意力的混合结构。</li><li><strong>Gemini</strong> 的架构据传也大量使用稀疏注意力来处理百万级别的上下文。</li></ul><p>现代长上下文模型（如支持 100K、1M token 上下文的模型），几乎都用到了混合注意力或类似的稀疏注意力变体。纯全注意力在那个长度上根本跑不动。</p><h2 id="怎么理解这种设计的直觉" tabindex="-1">怎么理解这种设计的直觉 <a class="header-anchor" href="#怎么理解这种设计的直觉" aria-label="Permalink to &quot;怎么理解这种设计的直觉&quot;">​</a></h2><p>把混合注意力想成一个<strong>高效团队</strong>：</p><ul><li>SWA 是一线员工，负责处理手头具体的任务，信息在团队内部高效流转。</li><li>GA 是项目经理，偶尔召集全员大会，把散布在各处的关键信息汇总起来。</li></ul><p>两者配合，才做到了既高效又有大局观。这其实是工程上很典型的&quot;分而治之&quot;思路：大事化小，小事化了，局部搞定了再全局整合。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>混合注意力的核心洞察是：<strong>不是所有 token 之间的关系都同等重要</strong>。相邻词之间要精读，远距离词之间偶尔拉通就够了。通过滑动窗口 + 全局注意力的组合，模型在计算量和建模能力之间找到了一个很好的平衡点。</p><p>理解了这个设计，你再看到&quot;这个模型支持 128K 上下文&quot;之类的宣传时，就能知道背后大概率不是傻傻的全注意力——而是巧妙的稀疏注意力在撑着。</p>',40)])])}const h=t(a,[["render",i]]);export{q as __pageData,h as default};
